import{_ as a,o as l,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"134. On Call Recall Allowance Non Catt","description":"","frontmatter":{"title":"134. On Call Recall Allowance Non Catt","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","allowances"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/134-on-call-recall-allowance-non-catt.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/134-on-call-recall-allowance-non-catt.md"}'),n={name:"ebas/mental-health/health-professionals/hours-of-work/134-on-call-recall-allowance-non-catt.md"};function r(s,e,c,i,h,p){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_134-on-call-recall-allowance-non-catt" tabindex="-1">134. On Call Recall Allowance Non Catt <a class="header-anchor" href="#_134-on-call-recall-allowance-non-catt" aria-label="Permalink to &quot;134. On Call Recall Allowance Non Catt&quot;">​</a></h1><p><strong>134.1</strong> On-call Allowance (non-CATT)</p><p><strong>(a)</strong> An Employee may be rostered to be &#39;on-call&#39;.</p><p><strong>(b)</strong> On-call means available to be recalled to duty in that period of time beyond the Employee&#39;s rostered hours of duty.</p><p><strong>(c)</strong> An Employee rostered to be on-call will be paid the &#39;on-call allowance&#39; set in Appendix 2 per 12-hour period of part thereof commencing with the following rates:</p><p><strong>(i)</strong> Monday to Friday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>;</p><p><strong>(ii)</strong> Saturday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>;</p><p><strong>(iii)</strong> Sunday or public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>; and</p><p><strong>(iv)</strong> Weekend public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(d)</strong> The telephone allowance in the 2020 Agreement does not apply from FFPPOA 20 May 2025 and has been included in the rates at 134.1(c) above.</p><p><strong>(e)</strong> An Employee rostered to be on-call for a period spanning two days over which two different on-call allowances apply will receive a payment which is equal to the allowance payable for the day attracting the higher allowance.</p><p><strong>134.2</strong> Recall - Return to Workplace If an Employee is recalled to duty during an off-duty period where the work is not continuous with the Employee&#39;s next succeeding rostered period of ordinary duty, such Employee will be paid a minimum of three hours’ pay at the applicable overtime rates.</p><p><strong>134.3</strong> Recall – Without Return to Workplace</p><p><strong>(a)</strong> Where recall to duty can be managed without the Employee returning to the workplace (for example by telephone), clause 134.2 will not apply and such Employee will be paid a minimum of one hour of overtime for such recall work.</p><p><strong>(b)</strong> For subsequent recalls beyond the first hour, the Employee will be paid a minimum of one hour of overtime, but multiple recalls within a discrete hour will not attract additional overtime.</p>',15)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
